-- Region XI (Davao): Davao del Norte, Davao de Oro, Davao City, Davao Oriental, Davao del Sur, Davao Occidental
-- BIR RDO 112(DelNorte+deOro split),113A/B(Davao City),114(Oriental),115(DelSur+Occidental split). Newest-DO-year-wins.
START TRANSACTION;
DELETE FROM zonal_values WHERE province IN ('DAVAO DEL NORTE','DAVAO DE ORO','DAVAO CITY','DAVAO ORIENTAL','DAVAO DEL SUR','DAVAO OCCIDENTAL');
COMMIT;
